// Close dropdown on click outside
useEffect(() => {
  function handleClickOutside(event) {
    if (downloadMenuRef.current && !downloadMenuRef.current.contains(event.target)) {
      setDownloadDropdownOpen(false);
    }
  }
  document.addEventListener("mousedown", handleClickOutside);
  return () => document.removeEventListener("mousedown", handleClickOutside);
}, []);

const triggerWeeklyCheck = (silent = false) => {
  setIsCheckingUpdates(true);
  if (!silent) {
    setUpdateNotification({
      type: 'info',
      message: 'Connecting to Beyond# Registry API...'
    });
  }

  setTimeout(() => {
    setIsCheckingUpdates(false);
    const now = new Date();
    localStorage.setItem('beyond_observatory_last_weekly_check', now.toISOString());

    setUpdateNotification({
      type: 'success',
      message: 'Weekly datasets updated successfully! ACLED, NBS & FAO indicators synchronized.'
    });

    setTimeout(() => {
      setUpdateNotification(null);
    }, 4000);
  }, 1500);
};

useEffect(() => {
  const lastCheck = localStorage.getItem('beyond_observatory_last_weekly_check');
  if (!lastCheck) {
    triggerWeeklyCheck(true);
  } else {
    const lastCheckDate = new Date(lastCheck);
    const oneWeekAgo = new Date();
    oneWeekAgo.setDate(oneWeekAgo.getDate() - 7);
    if (lastCheckDate < oneWeekAgo) {
      triggerWeeklyCheck(false);
    } else {
      setUpdateNotification({
        type: 'success',
        message: 'Weekly update verified: System is up-to-date.'
      });
      setTimeout(() => {
        setUpdateNotification(null);
      }, 3000);
    }
  }
}, []);

